SupplyBoxConfig = {}
SupplyBoxConfig.SupplyBox = {}

function SupplyBoxConfig:initConfig(configs)
    for _, config in pairs(configs) do
        local item = {}
        item.Id = tonumber(config.Id)
        item.Type = tonumber(config.Type)
        item.RefreshTime = tonumber(config.RefreshTime)
        item.RandomPoolId = tonumber(config.RandomPoolId)
        item.Image = config.Image or ""
        item.Rewards = RewardConfig:getRewardByIds(config.RewardIds)
       -- item.Rewards = StringUtil.split(config.RewardIds, "#")
        item.MoneyType = tonumber(config.MoneyType)
        item.Price = tonumber(config.Price)
        item.PriceA = tonumber(config.PriceA)
        item.PriceB = tonumber(config.PriceB)
        item.PriceC = tonumber(config.PriceC)
        item.StackCount = tonumber(config.StackCount or #item.Rewards)
        if config.RandomParams == "#" then
            item.RandomPoolParams = ""
        else
            item.RandomPoolParams = config.RandomParams
        end
        self.SupplyBox[item.Id] = item
    end
end

function SupplyBoxConfig:getSupplyById(supplyId)
    return self.SupplyBox[supplyId]
end

function SupplyBoxConfig:getSupplyByType(type)
    local supplies = {}
    for _, supply in pairs(self.SupplyBox) do
        if supply.Type == type then
            table.insert(supplies, supply)
        end
    end
    return supplies
end